window.__tinePages=[{"favorite":false,"journal":false,"slug":"feature-showcase","title":"Feature showcase"},{"favorite":false,"journal":false,"slug":"features-pdf-annotation","title":"Features/PDF annotation"},{"favorite":false,"journal":false,"slug":"features-quick-capture","title":"Features/Quick capture"},{"favorite":false,"journal":false,"slug":"features-sheets","title":"Features/Sheets"},{"favorite":false,"journal":false,"slug":"features-tips-shortcuts","title":"Features/Tips & shortcuts"},{"favorite":false,"journal":false,"slug":"project-roadmap","title":"Project/Roadmap"},{"favorite":false,"journal":false,"slug":"tine-guide","title":"Tine Guide"},{"favorite":true,"journal":false,"slug":"welcome-to-tine","title":"Welcome to Tine"}];
window.__tineBlocks=[{"anchor":"b0","slug":"feature-showcase","text":"This page exercises every Logseq page-level feature Tine knows about, so you can see exactly how each one renders — and where we're still rough. It's ordinary Logseq Markdown; the same file opens unchanged in Logseq.","title":"Feature showcase"},{"anchor":"b1","slug":"feature-showcase","text":"1 — Inline text formatting","title":"Feature showcase"},{"anchor":"b2","slug":"feature-showcase","text":"Bold, italic, also italic, strikethrough, inline code, highlight, and also highlight.","title":"Feature showcase"},{"anchor":"b3","slug":"feature-showcase","text":"A mix in one line: a bold code span, an italic link, and a struck highlight.","title":"Feature showcase"},{"anchor":"b4","slug":"feature-showcase","text":"Raw inline HTML renders (sanitized to a safe allowlist): , , + , , and / . Scripts and event handlers (onerror=, <script>) are stripped.","title":"Feature showcase"},{"anchor":"b5","slug":"feature-showcase","text":"Parity note: a tag glued to a word — H<sub>2</sub>O, mc<sup>2</sup> — stays literal in Logseq too (mldoc only starts inline HTML at a word boundary), and so do the Markdown carets x^2^ / H~2~O. For a glued subscript, use math: E = mc^2, H_2O.","title":"Feature showcase"},{"anchor":"b6","slug":"feature-showcase","text":"2 — Links & references","title":"Feature showcase"},{"anchor":"b7","slug":"feature-showcase","text":"Page link: Welcome to Tine · tag: #demo · namespaced page: Features/Quick capture.","title":"Feature showcase"},{"anchor":"b8","slug":"feature-showcase","text":"External link: the Logseq docs · bare URL: https://logseq.com · autolinked email: .","title":"Feature showcase"},{"anchor":"b9","slug":"feature-showcase","text":"Labelled page link: read the welcome.","title":"Feature showcase"},{"anchor":"00000000-0000-4000-8000-00000000feed","slug":"feature-showcase","text":"This block is a reference target.","title":"Feature showcase"},{"anchor":"b10","slug":"feature-showcase","text":"Block reference to it: .","title":"Feature showcase"},{"anchor":"b11","slug":"feature-showcase","text":"3 — Headings","title":"Feature showcase"},{"anchor":"b12","slug":"feature-showcase","text":"Heading 1","title":"Feature showcase"},{"anchor":"b13","slug":"feature-showcase","text":"Heading 2","title":"Feature showcase"},{"anchor":"b14","slug":"feature-showcase","text":"Heading 3","title":"Feature showcase"},{"anchor":"b15","slug":"feature-showcase","text":"Heading 4","title":"Feature showcase"},{"anchor":"b16","slug":"feature-showcase","text":"Heading 5","title":"Feature showcase"},{"anchor":"b17","slug":"feature-showcase","text":"Heading 6","title":"Feature showcase"},{"anchor":"b18","slug":"feature-showcase","text":"4 — Lists & nesting","title":"Feature showcase"},{"anchor":"b19","slug":"feature-showcase","text":"Parent bullet","title":"Feature showcase"},{"anchor":"b20","slug":"feature-showcase","text":"Child bullet","title":"Feature showcase"},{"anchor":"b21","slug":"feature-showcase","text":"Grandchild bullet","title":"Feature showcase"},{"anchor":"b22","slug":"feature-showcase","text":"Second child with a formatted tail","title":"Feature showcase"},{"anchor":"b23","slug":"feature-showcase","text":"Numbered list (logseq order):","title":"Feature showcase"},{"anchor":"b24","slug":"feature-showcase","text":"First","title":"Feature showcase"},{"anchor":"b25","slug":"feature-showcase","text":"Second","title":"Feature showcase"},{"anchor":"b26","slug":"feature-showcase","text":"Third","title":"Feature showcase"},{"anchor":"b27","slug":"feature-showcase","text":"5 — Block content types","title":"Feature showcase"},{"anchor":"b28","slug":"feature-showcase","text":"A blockquote. Logseq renders this with a left rule and muted text.","title":"Feature showcase"},{"anchor":"b29","slug":"feature-showcase","text":"Fenced code block with language highlighting:","title":"Feature showcase"},{"anchor":"b30","slug":"feature-showcase","text":"fn main() { let greeting = \"hello from Tine\"; println!(\"{greeting}\"); }","title":"Feature showcase"},{"anchor":"b31","slug":"feature-showcase","text":"A Markdown table:","title":"Feature showcase"},{"anchor":"b32","slug":"feature-showcase","text":"Feature Logseq Tine Tables yes ? Math yes ?","title":"Feature showcase"},{"anchor":"b33","slug":"feature-showcase","text":"Horizontal rule follows:","title":"Feature showcase"},{"anchor":"b35","slug":"feature-showcase","text":"Inline math E = mc^2 and display math:","title":"Feature showcase"},{"anchor":"b36","slug":"feature-showcase","text":"\\int_{-\\infty}^{\\infty} e^{-x^2}\\,dx = \\sqrt{\\pi}","title":"Feature showcase"},{"anchor":"b37","slug":"feature-showcase","text":"An inline image (sized): capture window","title":"Feature showcase"},{"anchor":"b38","slug":"feature-showcase","text":"6 — Tasks, priorities, scheduling","title":"Feature showcase"},{"anchor":"b39","slug":"feature-showcase","text":"A plain task marker","title":"Feature showcase"},{"anchor":"b40","slug":"feature-showcase","text":"A task in progress","title":"Feature showcase"},{"anchor":"b41","slug":"feature-showcase","text":"A finished task","title":"Feature showcase"},{"anchor":"b42","slug":"feature-showcase","text":"Deferred (now-workflow marker)","title":"Feature showcase"},{"anchor":"b43","slug":"feature-showcase","text":"Active (now-workflow marker)","title":"Feature showcase"},{"anchor":"b44","slug":"feature-showcase","text":"Blocked on someone else","title":"Feature showcase"},{"anchor":"b45","slug":"feature-showcase","text":"Abandoned task","title":"Feature showcase"},{"anchor":"b46","slug":"feature-showcase","text":"High-priority task","title":"Feature showcase"},{"anchor":"b47","slug":"feature-showcase","text":"Medium-priority task","title":"Feature showcase"},{"anchor":"b48","slug":"feature-showcase","text":"Low-priority task","title":"Feature showcase"},{"anchor":"b49","slug":"feature-showcase","text":"A scheduled task","title":"Feature showcase"},{"anchor":"b50","slug":"feature-showcase","text":"A task with a deadline","title":"Feature showcase"},{"anchor":"b51","slug":"feature-showcase","text":"A repeating task","title":"Feature showcase"},{"anchor":"b52","slug":"feature-showcase","text":"A task with a logbook (time tracking)","title":"Feature showcase"},{"anchor":"b53","slug":"feature-showcase","text":"7 — Block properties","title":"Feature showcase"},{"anchor":"b54","slug":"feature-showcase","text":"A block carrying its own properties.","title":"Feature showcase"},{"anchor":"b55","slug":"feature-showcase","text":"8 — Embeds","title":"Feature showcase"},{"anchor":"b56","slug":"feature-showcase","text":"Page embed of another demo page:","title":"Feature showcase"},{"anchor":"b58","slug":"feature-showcase","text":"Block embed of the reference target above:","title":"Feature showcase"},{"anchor":"b60","slug":"feature-showcase","text":"9 — Queries","title":"Feature showcase"},{"anchor":"b61","slug":"feature-showcase","text":"Simple query — every TODO task in this graph:","title":"Feature showcase"},{"anchor":"b63","slug":"feature-showcase","text":"Simple query — blocks referencing a page:","title":"Feature showcase"},{"anchor":"b65","slug":"feature-showcase","text":"Query by priority:","title":"Feature showcase"},{"anchor":"b67","slug":"feature-showcase","text":"Compound query (and / or / not) — TODO tasks that are also high priority:","title":"Feature showcase"},{"anchor":"b69","slug":"feature-showcase","text":"10 — Macros, renderers & callouts","title":"Feature showcase"},{"anchor":"b70","slug":"feature-showcase","text":"Video embed:","title":"Feature showcase"},{"anchor":"b71","slug":"feature-showcase","text":"Namespace macro:","title":"Feature showcase"},{"anchor":"b72","slug":"feature-showcase","text":"A NOTE callout:","title":"Feature showcase"},{"anchor":"b73","slug":"feature-showcase","text":"Callouts (admonitions) group a highlighted aside. This is a NOTE.","title":"Feature showcase"},{"anchor":"b74","slug":"feature-showcase","text":"A footnote reference in a sentence.","title":"Feature showcase"},{"anchor":"b75","slug":"feature-showcase","text":"And here is the footnote body.","title":"Feature showcase"},{"anchor":"b76","slug":"feature-showcase","text":"Create one yourself","title":"Feature showcase"},{"anchor":"b77","slug":"feature-showcase","text":"1. Make a scratch page and add one bullet per construct you want to test: links, tables, code, tasks, embeds, queries, and callouts.","title":"Feature showcase"},{"anchor":"b78","slug":"feature-showcase","text":"2. Keep each example small and label it with a heading so it is easy to scan.","title":"Feature showcase"},{"anchor":"b79","slug":"feature-showcase","text":"3. Add page properties such as title:: or icon:: at the top when the whole page needs metadata.","title":"Feature showcase"},{"anchor":"b80","slug":"feature-showcase","text":"4. What you should see: each example renders live while staying ordinary Logseq Markdown.","title":"Feature showcase"},{"anchor":"b0","slug":"features-pdf-annotation","text":"PDF annotation","title":"Features/PDF annotation"},{"anchor":"b1","slug":"features-pdf-annotation","text":"Open a PDF that lives in your graph's assets/ (or drop one in) and read it in a side pane right next to your notes.","title":"Features/PDF annotation"},{"anchor":"b2","slug":"features-pdf-annotation","text":"Select text in the PDF to highlight it; click a highlight again to change its color.","title":"Features/PDF annotation"},{"anchor":"b3","slug":"features-pdf-annotation","text":"Ctrl+drag a rectangle to clip a figure or an equation as an image highlight.","title":"Features/PDF annotation"},{"anchor":"b4","slug":"features-pdf-annotation","text":"Every highlight becomes a block on a notes page named after the PDF, so you can write underneath it, link it, and reference it like any other bullet — and each note jumps straight back to its spot in the document.","title":"Features/PDF annotation"},{"anchor":"b5","slug":"features-pdf-annotation","text":"It's how you turn a paper into linked, searchable notes without ever leaving Tine.","title":"Features/PDF annotation"},{"anchor":"b6","slug":"features-pdf-annotation","text":"Create one yourself","title":"Features/PDF annotation"},{"anchor":"b7","slug":"features-pdf-annotation","text":"1. Put a PDF in your graph's assets/ folder, or drop it into a page.","title":"Features/PDF annotation"},{"anchor":"b8","slug":"features-pdf-annotation","text":"2. Open the PDF from its asset link so it appears in the side pane.","title":"Features/PDF annotation"},{"anchor":"b9","slug":"features-pdf-annotation","text":"3. Select text to create a highlight, or hold Ctrl and drag a rectangle for an area highlight.","title":"Features/PDF annotation"},{"anchor":"b10","slug":"features-pdf-annotation","text":"4. Write notes under the generated highlight blocks.","title":"Features/PDF annotation"},{"anchor":"b11","slug":"features-pdf-annotation","text":"5. What you should see: each highlight is a normal block that links back to the exact PDF location.","title":"Features/PDF annotation"},{"anchor":"b0","slug":"features-quick-capture","text":"Global quick-capture","title":"Features/Quick capture"},{"anchor":"b1","slug":"features-quick-capture","text":"A passing thought shouldn't make you switch windows. Bind a desktop shortcut and a small always-on-top capture box pops up over any app — with the full Tine editor — and files what you type straight into your graph. Tine doesn't even need to be focused.","title":"Features/Quick capture"},{"anchor":"b2","slug":"features-quick-capture","text":"What it looks like","title":"Features/Quick capture"},{"anchor":"b3","slug":"features-quick-capture","text":"The quick-capture window — note the optional page-title field at the top","title":"Features/Quick capture"},{"anchor":"b4","slug":"features-quick-capture","text":"Set it up (Linux, one time)","title":"Features/Quick capture"},{"anchor":"b5","slug":"features-quick-capture","text":"Tine listens for a launch with the --capture flag, so bind a global keyboard shortcut in your desktop environment to run tine --capture:","title":"Features/Quick capture"},{"anchor":"b6","slug":"features-quick-capture","text":"GNOME — Settings → Keyboard → View and Customize Shortcuts → Custom Shortcuts → +. Command: tine --capture. Pick a key like Super+N.","title":"Features/Quick capture"},{"anchor":"b7","slug":"features-quick-capture","text":"KDE — System Settings → Shortcuts → Add → Command/URL. Command: tine --capture.","title":"Features/Quick capture"},{"anchor":"b8","slug":"features-quick-capture","text":"Other desktops — add a custom keyboard shortcut that runs tine --capture. Use the binary's full path if it isn't on your PATH.","title":"Features/Quick capture"},{"anchor":"b9","slug":"features-quick-capture","text":"Now press your shortcut from anywhere — the box appears, you type, and it's saved.","title":"Features/Quick capture"},{"anchor":"b10","slug":"features-quick-capture","text":"Where your capture goes","title":"Features/Quick capture"},{"anchor":"b11","slug":"features-quick-capture","text":"Leave the title empty → the text is appended to today's journal. This is the fast path: hotkey, type, done.","title":"Features/Quick capture"},{"anchor":"b12","slug":"features-quick-capture","text":"Type a page title (the field at the top of the window) → it's filed to that page instead, created if it doesn't exist yet. Perfect for \"add this to my Reading notes\" without leaving what you're doing.","title":"Features/Quick capture"},{"anchor":"b13","slug":"features-quick-capture","text":"It's the real editor in there: [[ page links, # tags, / slash commands, and nested bullets all work.","title":"Features/Quick capture"},{"anchor":"b14","slug":"features-quick-capture","text":"Create one yourself","title":"Features/Quick capture"},{"anchor":"b15","slug":"features-quick-capture","text":"1. Open your desktop environment's keyboard-shortcut settings.","title":"Features/Quick capture"},{"anchor":"b16","slug":"features-quick-capture","text":"2. Add a custom shortcut whose command is tine --capture.","title":"Features/Quick capture"},{"anchor":"b17","slug":"features-quick-capture","text":"3. Press the shortcut while another app is focused, then type a quick note.","title":"Features/Quick capture"},{"anchor":"b18","slug":"features-quick-capture","text":"4. Leave the title empty for today's journal, or type a page title to file it there.","title":"Features/Quick capture"},{"anchor":"b19","slug":"features-quick-capture","text":"5. What you should see: the capture box saves real Logseq bullets into your graph without switching windows.","title":"Features/Quick capture"},{"anchor":"b20","slug":"features-quick-capture","text":"Tune the Enter key","title":"Features/Quick capture"},{"anchor":"b21","slug":"features-quick-capture","text":"By default Enter starts a new bullet and Ctrl+Shift+Enter files the capture (so you can jot several lines first). Prefer Enter-to-file? Open Settings and flip Quick-capture: Enter key.","title":"Features/Quick capture"},{"anchor":"b22","slug":"features-quick-capture","text":"The box auto-grows as you type, and it keeps your draft if it loses focus — only Esc or filing it clears the text.","title":"Features/Quick capture"},{"anchor":"b0","slug":"features-sheets","text":"Sheets","title":"Features/Sheets"},{"anchor":"b1","slug":"features-sheets","text":"Sheets turn ordinary outline branches into 2-D views. The same file still opens in Logseq as nested bullets with harmless tine.* properties.","title":"Features/Sheets"},{"anchor":"b2","slug":"features-sheets","text":"Formula columns derive values live (the Typed reading list below computes effort from rating); derived values are shown, never written onto the rows.","title":"Features/Sheets"},{"anchor":"b3","slug":"features-sheets","text":"Positional grid","title":"Features/Sheets"},{"anchor":"b5","slug":"features-sheets","text":"Area","title":"Features/Sheets"},{"anchor":"b6","slug":"features-sheets","text":"Owner","title":"Features/Sheets"},{"anchor":"b7","slug":"features-sheets","text":"Notes","title":"Features/Sheets"},{"anchor":"b9","slug":"features-sheets","text":"Spec","title":"Features/Sheets"},{"anchor":"b10","slug":"features-sheets","text":"Martin","title":"Features/Sheets"},{"anchor":"b11","slug":"features-sheets","text":"Nested sub-grid","title":"Features/Sheets"},{"anchor":"b13","slug":"features-sheets","text":"Risk","title":"Features/Sheets"},{"anchor":"b14","slug":"features-sheets","text":"Mitigation","title":"Features/Sheets"},{"anchor":"b16","slug":"features-sheets","text":"Scope drift","title":"Features/Sheets"},{"anchor":"b17","slug":"features-sheets","text":"Keep v1 narrow","title":"Features/Sheets"},{"anchor":"b19","slug":"features-sheets","text":"Build","title":"Features/Sheets"},{"anchor":"b20","slug":"features-sheets","text":"Codex","title":"Features/Sheets"},{"anchor":"b21","slug":"features-sheets","text":"Ragged rows are fine","title":"Features/Sheets"},{"anchor":"b23","slug":"features-sheets","text":"Empty middle cell","title":"Features/Sheets"},{"anchor":"b25","slug":"features-sheets","text":"Still round-trips","title":"Features/Sheets"},{"anchor":"b26","slug":"features-sheets","text":"Create one yourself — grid","title":"Features/Sheets"},{"anchor":"b27","slug":"features-sheets","text":"1. Create a heading block for the thing you want to compare, for example ## Reading plan.","title":"Features/Sheets"},{"anchor":"b28","slug":"features-sheets","text":"2. Add tine.view:: grid under that heading. Add tine.header:: true if the first row should be column labels.","title":"Features/Sheets"},{"anchor":"b29","slug":"features-sheets","text":"3. Add child bullets for rows. Inside each row, add one child bullet per cell.","title":"Features/Sheets"},{"anchor":"b30","slug":"features-sheets","text":"4. Drag row or cell bullets to reshape the outline; the grid follows the tree.","title":"Features/Sheets"},{"anchor":"b31","slug":"features-sheets","text":"5. What you should see: a live grid whose cells are still ordinary Logseq bullets.","title":"Features/Sheets"},{"anchor":"b32","slug":"features-sheets","text":"Task table","title":"Features/Sheets"},{"anchor":"b33","slug":"features-sheets","text":"Draft the sheet docs #sheets-demo","title":"Features/Sheets"},{"anchor":"b34","slug":"features-sheets","text":"Polish cell menus #sheets-demo","title":"Features/Sheets"},{"anchor":"b35","slug":"features-sheets","text":"Add aggregate footer #sheets-demo","title":"Features/Sheets"},{"anchor":"b36","slug":"features-sheets","text":"Create one yourself — table","title":"Features/Sheets"},{"anchor":"b37","slug":"features-sheets","text":"1. Create a parent block and add tine.view:: table under it.","title":"Features/Sheets"},{"anchor":"b38","slug":"features-sheets","text":"2. Add one child bullet per row. Put properties such as owner:: Martin or estimate:: 2 on each row.","title":"Features/Sheets"},{"anchor":"b39","slug":"features-sheets","text":"3. Optional: add tine.col-aggregates:: prop:estimate=sum to sum a numeric property in the footer.","title":"Features/Sheets"},{"anchor":"b40","slug":"features-sheets","text":"4. What you should see: each child bullet becomes a row, and properties become editable table columns.","title":"Features/Sheets"},{"anchor":"b41","slug":"features-sheets","text":"Typed reading list","title":"Features/Sheets"},{"anchor":"b42","slug":"features-sheets","text":"Bases study","title":"Features/Sheets"},{"anchor":"b43","slug":"features-sheets","text":"CSV import notes","title":"Features/Sheets"},{"anchor":"b44","slug":"features-sheets","text":"Create one yourself — formula","title":"Features/Sheets"},{"anchor":"b45","slug":"features-sheets","text":"1. Start with a table that has a numeric or enum field, for example rating=number in tine.fields::.","title":"Features/Sheets"},{"anchor":"b46","slug":"features-sheets","text":"2. Right-click a column header and choose Add/Edit formula.","title":"Features/Sheets"},{"anchor":"b47","slug":"features-sheets","text":"3. Use the visual formula builder faces: pick a field, add a comparison, and combine it with IF / THEN / ELSE.","title":"Features/Sheets"},{"anchor":"b48","slug":"features-sheets","text":"4. Use the </> raw toggle when you want to type the expression directly, such as rating * 2.","title":"Features/Sheets"},{"anchor":"b49","slug":"features-sheets","text":"5. What you should see: a read-only computed column whose values evaluate live and are not written onto the rows.","title":"Features/Sheets"},{"anchor":"b50","slug":"features-sheets","text":"Task board","title":"Features/Sheets"},{"anchor":"b52","slug":"features-sheets","text":"Create one yourself — query","title":"Features/Sheets"},{"anchor":"b53","slug":"features-sheets","text":"1. Type /Query and create a query for the blocks you want, such as tasks tagged #sheets-demo.","title":"Features/Sheets"},{"anchor":"b54","slug":"features-sheets","text":"2. Keep the query in one block, then add tine.view:: table or tine.view:: board under that same block.","title":"Features/Sheets"},{"anchor":"b55","slug":"features-sheets","text":"3. For a board, add tine.group-by:: state or another property/tag axis.","title":"Features/Sheets"},{"anchor":"b56","slug":"features-sheets","text":"4. What you should see: query results render as a live sheet view without copying the source blocks.","title":"Features/Sheets"},{"anchor":"b57","slug":"features-sheets","text":"Create one yourself — board","title":"Features/Sheets"},{"anchor":"b58","slug":"features-sheets","text":"1. Create a parent block and add tine.view:: board.","title":"Features/Sheets"},{"anchor":"b59","slug":"features-sheets","text":"2. Add tine.group-by:: state, tine.group-by:: tags, or a property name to choose the columns.","title":"Features/Sheets"},{"anchor":"b60","slug":"features-sheets","text":"3. Add child bullets, or put the board properties under a query block to board over query results.","title":"Features/Sheets"},{"anchor":"b61","slug":"features-sheets","text":"4. What you should see: cards group into columns while staying normal outline blocks underneath.","title":"Features/Sheets"},{"anchor":"b62","slug":"features-sheets","text":"Topic board","title":"Features/Sheets"},{"anchor":"b63","slug":"features-sheets","text":"Schema menu polish #schema #sheets-demo","title":"Features/Sheets"},{"anchor":"b64","slug":"features-sheets","text":"CSV drop walkthrough #interop #sheets-demo","title":"Features/Sheets"},{"anchor":"b0","slug":"features-tips-shortcuts","text":"Tips & shortcuts","title":"Features/Tips & shortcuts"},{"anchor":"b1","slug":"features-tips-shortcuts","text":"A quick tour of the things that aren't obvious on day one. (Shortcuts are remappable in Settings.)","title":"Features/Tips & shortcuts"},{"anchor":"b2","slug":"features-tips-shortcuts","text":"Find anything — Ctrl+K","title":"Features/Tips & shortcuts"},{"anchor":"b3","slug":"features-tips-shortcuts","text":"Ctrl+K opens the quick switcher: jump to a page, search the text of any block, or run a command — all from one box. Ctrl+Shift+P opens the command palette (commands only).","title":"Features/Tips & shortcuts"},{"anchor":"b4","slug":"features-tips-shortcuts","text":"Create one yourself","title":"Features/Tips & shortcuts"},{"anchor":"b5","slug":"features-tips-shortcuts","text":"1. Press Ctrl+K.","title":"Features/Tips & shortcuts"},{"anchor":"b6","slug":"features-tips-shortcuts","text":"2. Type part of a page name, a block phrase, or a command such as Open Guide.","title":"Features/Tips & shortcuts"},{"anchor":"b7","slug":"features-tips-shortcuts","text":"3. Press Enter on the highlighted result.","title":"Features/Tips & shortcuts"},{"anchor":"b8","slug":"features-tips-shortcuts","text":"4. What you should see: Tine jumps to the page/block or runs the command without leaving your graph.","title":"Features/Tips & shortcuts"},{"anchor":"b9","slug":"features-tips-shortcuts","text":"Slash commands — /","title":"Features/Tips & shortcuts"},{"anchor":"b10","slug":"features-tips-shortcuts","text":"Type / at the start of a bullet for a menu: tasks, headings, a code block, a /calc live calculator, dates (Scheduled / Deadline), callouts, queries, a math block, asset upload, and more.","title":"Features/Tips & shortcuts"},{"anchor":"b11","slug":"features-tips-shortcuts","text":"Tabs","title":"Features/Tips & shortcuts"},{"anchor":"b12","slug":"features-tips-shortcuts","text":"Middle-click any bullet, page, or search result to open it in a background tab. Double-click a tab to pin it, drag to reorder, Ctrl+W to close. Your tabs come back next launch.","title":"Features/Tips & shortcuts"},{"anchor":"b13","slug":"features-tips-shortcuts","text":"The sidebars","title":"Features/Tips & shortcuts"},{"anchor":"b14","slug":"features-tips-shortcuts","text":"t l toggles the left sidebar — journals, favorites, recents, all pages, and a namespace tree. t r toggles the right sidebar; Shift-click any bullet's dot to open it there and keep it beside your work.","title":"Features/Tips & shortcuts"},{"anchor":"b15","slug":"features-tips-shortcuts","text":"Focus mode & dimming — t f / t b","title":"Features/Tips & shortcuts"},{"anchor":"b16","slug":"features-tips-shortcuts","text":"t f (focus mode) hides the sidebars and toolbar so the screen is just your text; layered Esc steps back out.","title":"Features/Tips & shortcuts"},{"anchor":"b17","slug":"features-tips-shortcuts","text":"t b (dim inactive blocks) fades everything except the bullet you're editing — a typewriter-style spotlight. Use it on its own, or let focus mode turn it on for you.","title":"Features/Tips & shortcuts"},{"anchor":"b18","slug":"features-tips-shortcuts","text":"A few more worth knowing","title":"Features/Tips & shortcuts"},{"anchor":"b19","slug":"features-tips-shortcuts","text":"Carry unfinished tasks forward into today (from the command palette) — the last 7 / 30 / 365 days, optionally with their context.","title":"Features/Tips & shortcuts"},{"anchor":"b20","slug":"features-tips-shortcuts","text":"Namespaces: name a page Project/Roadmap and it nests under Project in the sidebar. This page lives under Features.","title":"Features/Tips & shortcuts"},{"anchor":"b21","slug":"features-tips-shortcuts","text":"Page icons: add a property like icon:: 📚 at the very top of a page — that's where the ⌨️ on this one comes from.","title":"Features/Tips & shortcuts"},{"anchor":"b22","slug":"features-tips-shortcuts","text":"Interface zoom with Ctrl + / - / 0, and PDFs, images, and audio all have their own controls.","title":"Features/Tips & shortcuts"},{"anchor":"b0","slug":"project-roadmap","text":"Project / Roadmap","title":"Project/Roadmap"},{"anchor":"b1","slug":"project-roadmap","text":"This page lives in the Project namespace, and it doubles as the target for the reference and the embed over on Welcome to Tine.","title":"Project/Roadmap"},{"anchor":"7a1c0f5e-0000-4000-8000-000000000001","slug":"project-roadmap","text":"Tine round-trips your files byte-for-byte, so you can always switch back to Logseq — nothing here is one-way.","title":"Project/Roadmap"},{"anchor":"b2","slug":"project-roadmap","text":"See the little count badge on the bullet above? That's how many blocks reference it — click the badge to see them.","title":"Project/Roadmap"},{"anchor":"b3","slug":"project-roadmap","text":"A few example tasks","title":"Project/Roadmap"},{"anchor":"b4","slug":"project-roadmap","text":"Write my first real note in Tine","title":"Project/Roadmap"},{"anchor":"b5","slug":"project-roadmap","text":"Set up the quick-capture hotkey — see Features/Quick capture","title":"Project/Roadmap"},{"anchor":"b6","slug":"project-roadmap","text":"Open my own Logseq graph and look around","title":"Project/Roadmap"},{"anchor":"b0","slug":"tine-guide","text":"Tine Guide","title":"Tine Guide"},{"anchor":"b1","slug":"tine-guide","text":"Open this Guide beside your own graph when you want live examples without switching graphs.","title":"Tine Guide"},{"anchor":"b2","slug":"tine-guide","text":"Each page is read-only here. Use Copy the guide into your graph on any Guide page when you want an editable, interlinked sandbox under tine-guide/.","title":"Tine Guide"},{"anchor":"b3","slug":"tine-guide","text":"Start here","title":"Tine Guide"},{"anchor":"b4","slug":"tine-guide","text":"Features/Sheets — create grids, tables, boards, queries, and formulas over ordinary bullets.","title":"Tine Guide"},{"anchor":"b5","slug":"tine-guide","text":"Features/Quick capture — set up a global capture box that files notes into your graph.","title":"Tine Guide"},{"anchor":"b6","slug":"tine-guide","text":"Features/PDF annotation — highlight PDFs and turn those highlights into linked note blocks.","title":"Tine Guide"},{"anchor":"b7","slug":"tine-guide","text":"Features/Tips & shortcuts — learn Ctrl+K, slash commands, tabs, sidebars, focus mode, and daily shortcuts.","title":"Tine Guide"},{"anchor":"b8","slug":"tine-guide","text":"Feature showcase — inspect one live example of each supported Logseq rendering feature.","title":"Tine Guide"},{"anchor":"b9","slug":"tine-guide","text":"Create one yourself","title":"Tine Guide"},{"anchor":"b10","slug":"tine-guide","text":"1. Open one of the Guide pages above and follow its numbered steps.","title":"Tine Guide"},{"anchor":"b11","slug":"tine-guide","text":"2. Use Copy the guide into your graph when you want an editable sandbox.","title":"Tine Guide"},{"anchor":"b12","slug":"tine-guide","text":"3. Tine creates the real tine-guide/ namespace, rewrites guide links to that copy, and leaves existing copied pages untouched.","title":"Tine Guide"},{"anchor":"b13","slug":"tine-guide","text":"4. What you should see: normal Logseq pages you can edit, delete, or keep as a reference.","title":"Tine Guide"},{"anchor":"b0","slug":"welcome-to-tine","text":"Welcome to Tine 👋","title":"Welcome to Tine"},{"anchor":"b1","slug":"welcome-to-tine","text":"Tine is a fast, local outliner that reads and writes the same Markdown files as Logseq — the very folder you point it at. Edit here or in Logseq; it's one graph, no import, no export. We have a lot of respect for Logseq — Tine just tries to improve a few things.","title":"Welcome to Tine"},{"anchor":"b2","slug":"welcome-to-tine","text":"Everything you see here is a real Markdown file in this graph's pages/ folder. Open that folder in your file manager and look — nothing is locked away.","title":"Welcome to Tine"},{"anchor":"b3","slug":"welcome-to-tine","text":"Try the basics right now","title":"Welcome to Tine"},{"anchor":"b4","slug":"welcome-to-tine","text":"Click any bullet to edit it. Enter makes a new bullet, Tab indents, Shift+Tab outdents. Drag a bullet's dot to move it (and everything under it).","title":"Welcome to Tine"},{"anchor":"b5","slug":"welcome-to-tine","text":"Tasks — type TODO / DOING / DONE at the start of a bullet, or press Ctrl+Enter to cycle one:","title":"Welcome to Tine"},{"anchor":"b6","slug":"welcome-to-tine","text":"Click this checkbox to complete me","title":"Welcome to Tine"},{"anchor":"b7","slug":"welcome-to-tine","text":"This one is already done","title":"Welcome to Tine"},{"anchor":"b8","slug":"welcome-to-tine","text":"Rich text: bold, italic, highlight, inline code, and even math like e^{i\\pi} + 1 = 0.","title":"Welcome to Tine"},{"anchor":"b9","slug":"welcome-to-tine","text":"Links: type [[ to link a page or # for a #tag. Here's a link to Project/Roadmap — click it.","title":"Welcome to Tine"},{"anchor":"b10","slug":"welcome-to-tine","text":"Block references & embeds","title":"Welcome to Tine"},{"anchor":"b11","slug":"welcome-to-tine","text":"Every bullet has a hidden id, so you can point at one specific bullet from anywhere. This is a live reference to a bullet over on the Roadmap:","title":"Welcome to Tine"},{"anchor":"b12","slug":"welcome-to-tine","text":"And here is that same bullet embedded inline — it stays in sync with the original:","title":"Welcome to Tine"},{"anchor":"b14","slug":"welcome-to-tine","text":"Keep exploring","title":"Welcome to Tine"},{"anchor":"b15","slug":"welcome-to-tine","text":"Tine Guide — open the in-app how-to guide beside your own graph, with live examples you can copy into a sandbox.","title":"Welcome to Tine"},{"anchor":"b16","slug":"welcome-to-tine","text":"Features/Quick capture — drop a thought into your graph from any app with a global hotkey. (Set this one up — it's genuinely good.)","title":"Welcome to Tine"},{"anchor":"b17","slug":"welcome-to-tine","text":"Features/Tips & shortcuts — slash commands, the command palette, tabs, the sidebar, focus mode and dimming.","title":"Welcome to Tine"},{"anchor":"b18","slug":"welcome-to-tine","text":"Features/Sheets — grids, field tables, and task boards over plain bullets.","title":"Welcome to Tine"},{"anchor":"b19","slug":"welcome-to-tine","text":"Features/PDF annotation — highlight PDFs and turn them into linked notes.","title":"Welcome to Tine"},{"anchor":"b20","slug":"welcome-to-tine","text":"When you're ready, point Tine at your own Logseq graph: open Settings (t s) and pick a different folder. Your notes stay exactly where they are.","title":"Welcome to Tine"}];
